.script-item-control[data-v-6b5a9243] {
  gap: 3px;
}
/* 使用V1的样式 */
.script-item[data-v-6b5a9243] {
  width: 100%;
  border: 1px solid var(--SmartThemeBorderColor);
  border-radius: 10px;
  min-height: 35px;
  display: flex;
  justify-content: space-between;
  flex-wrap: nowrap;
  align-items: center;
  padding: 0 5px;
}
